var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"이런 걸, 이런 걸 바란 게 아니었는데……. 이런 건 아니었어……. 이런 건…….","JPN":"こんなことを、こんなことを望んだわけではない……\\nこんなはずではない……こんな……","ENG":"I... didn’t wish... for any of this...","TWN":"不是這樣的，這不是我想要的……不是……不是這樣……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……지아야, 보이니?","JPN":"……ユイ、見えるか？","ENG":"Jia... Do you see it?","TWN":"……小佳，你有看到嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"인간은……. 이렇게 쉽게 상처 입는 나약한 종이란다.","JPN":"人間は……いとも簡単に傷ついてしまう、弱い生き物だ。","ENG":"Us humans... We are fragile beings.","TWN":"人類……就是如此軟弱無能的族類。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"상처 입기 두려운 나머지, 자신과 다른 존재를 구별하고 솎아내려 하지.","JPN":"傷つくことを恐れるあまり、自分とは異なる存在を区別し、排除しようとする。","ENG":"For fear of getting hurt, we try to differentiate ourselves from others unlike us.","TWN":"所以害怕受傷之餘，還會排擠和自己不同的種類。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"이 할애비는, 지아가 그런 사람들을 도와 주면 좋겠구나.","JPN":"おじいちゃんは、お前にそんな人たちを助けてほしいんだ。","ENG":"Your grandpa wishes... that you help these people, Jia.","TWN":"\\n爺爺希望小佳可以幫助這樣的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"그러니 <color=#ffd34c>더 나은 세상을 위해</color>…….","JPN":"だから、<color=#ffd34c>より良い世界のために</color>……","ENG":"Therefore, <color=#ffd34c>for a better world</color>...","TWN":"所以，<color=#ffd34c>為了更好的未來</color>……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CEO_NPC_ALPHA_NULL","text":{"KOREA":"……전부 잊어 버려라.","JPN":"……すべて忘れなさい。","ENG":"...forget everything.","TWN":"……這些事你全都忘了吧"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>어떤 일이 있어도……. 다시는 그걸 펼쳐서는 안 돼.</color>","JPN":"<color=#ff3636>どんなことがあっても……二度とそれを広げてはならない。</color>","ENG":"<color=#ff3636>No matter what... You mustn’t reveal them again.</color>","TWN":"<color=#ff3636>無論發生什麼事……都不能使用它！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>내 말, 무슨 뜻인지 알지?</color>","JPN":"<color=#ff3636>私の言葉がどういう意味か、わかるね？</color>","ENG":"<color=#ff3636>Do you understand?</color>","TWN":"<color=#ff3636>你有聽懂我的意思吧？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"subtitle","speaker":null,"text":{"KOREA":"12:24 그라운드 원 \\n코핀 컴퍼니 인근, 카페 스트레가","JPN":"12:24 グラウンド・ワン \\nコフィンカンパニー付近、カフェストレガ","ENG":"12:24 Ground One\\nNear Coffin Company, Cafe Strega","TWN":"12:24 G1 \\n科芬公司附近，史特雷加咖啡館"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오오! 지아 양, 오랜만일세!","JPN":"おお、ユイ君。久しぶりじゃないか！","ENG":"Ooh! Jia! Long time no see!","TWN":"哇喔！沈佳，好久不見啦！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그라운드 원에는 어쩐 일인가? 그간 별일 없었고?","JPN":"グラウンド・ワンには何の用かね？　元気にしていたか？","ENG":"How’ve you been? What brings you here to Ground One?","TWN":"你怎麼會來G1？你還好嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음? 안색이 그리 좋지 않군.","JPN":"おや？　顔色があまりよくないな。","ENG":"Hmm? Is something wrong?","TWN":"嗯？我看你臉色好像不太好欸？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뉴스에 나온 사내 분쟁 사건은 나도 들었네만, 혹시 그것 때문인가?","JPN":"ニュースに流れていた社内抗争については聞いているぞ。\\nもしかして、そのせいか？","ENG":"I heard about what happened on the news. Is it because of that?","TWN":"我有在新聞上看到公司爭權事件的消息，是因為這件事嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님이라면…….","JPN":"社長なら……","ENG":"I thought...","TWN":"老闆……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님이라면, 제가 어떤 선택을 해야 할지 알려 주실 것 같아서…….","JPN":"社長なら、私がどんな選択をすべきか教えてくれると思って……","ENG":"I thought you’d know what to do if you were in my shoes...","TWN":"如果是老闆，應該可以告訴我該怎麼選擇……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그래서…… 이렇게 갑작스럽게 찾아왔어요.","JPN":"それで……こうして急に訪ねてしまいました。","ENG":"And... that’s why I’m here.","TWN":"所以……就突然跑來找你。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"선택이라니? 자세히 말해 주겠나?","JPN":"選択だって？　詳しく教えてくれないか？","ENG":"What I would do? Could you elaborate?","TWN":"什麼選擇？可以請你說清楚一點嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그게…….","JPN":"それが……","ENG":"Well...","TWN":"就是……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런! 그런 일에 시달렸는데 왜 바로 연락하지 않은 건가?","JPN":"まったく、そんな大変なことがあったのに、どうしてすぐに\\n連絡をくれなかったんだ？","ENG":"What?! You went through all that and didn’t even bother to call me?","TWN":"什麼！你遇到這種事，怎麼沒有第一時間找我呢？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"겨우 그런 일 때문에…… 사장님께 폐를 끼치고 싶지 않아서요.","JPN":"たかがこんなことで……社長に迷惑をかけたくなかったのです。","ENG":"I didn’t want to bother you... with such a trivial matter...","TWN":"我不想因為這種小事……而麻煩老闆。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 일이라니, 우린 <color=#ffd34c>친구</color> 사이지 않은가.","JPN":"たかがこんなことだなんて、私たちは<color=#ffd34c>友達</color>じゃないか。","ENG":"Trivial matter? But we’re <color=#ffd34c>friends</color>, are we not?","TWN":"什麼叫這種小事，我們不是<color=#ffd34c>朋友</color>嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러니 앞으로는 꼭 연락하게나. 다음에도 그러면 나도 가만 있지 않을 걸세.","JPN":"だからこれからは必ず連絡してくれ。\\n今度また同じようなことがあったら私も黙ってはいないから。","ENG":"So if anything like that happens again, don’t hesitate to call me. I’m going to get angry at you if you don’t.","TWN":"所以下次你一定要跟我說，下次再有這種事，我絕對不會坐視不管的！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……사장님.","JPN":"……社長。","ENG":"Sir...","TWN":"……老闆。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"예전에 물어 보셨죠? 저 자신이 뭘 하고 싶은지를요.","JPN":"以前、聞いてくださいましたね。私自身が何をしたいかを。","ENG":"You asked me a long time ago what I wanted to do, remember?","TWN":"老闆，你之前問過我想做什麼。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음. 그렇군. 지아 양이 도망가 버리는 바람에 대답은 듣지 못했지.","JPN":"ああ、そうだな。君に逃げられてしまったから返事は聞けなかったが。","ENG":"Hmm. I did. But I never got an answer back because you ran away.","TWN":"嗯嗯，對啊，但後來你就跑掉了，所以我沒聽到你的回答。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 분위기에 휩쓸린 낯부끄러운 질문이었다고는 생각하지만 말이야. 하. 하. 하.","JPN":"まあ、その時は雰囲気にのまれて恥ずかしい質問をしてしまったよ。\\nハ・ハ・ハ。","ENG":"Well, afterwards, I also thought it was an embarrassing question to ask. Hah. Hah. Hah.","TWN":"雖然我問的當下氣氛有點尷尬啦，哈 哈 哈。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 뒤로 계속…… 계속 혼자서 생각해 봤어요.","JPN":"あれからずっと……ずっと、一人で考えてみました。","ENG":"After that day... I kept thinking about it.","TWN":"那之後……我一直在想這個問題。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저 스스로가 뭘 하고 싶은 건지요.","JPN":"私自身が何をしたいかを。","ENG":"Of what I wanted to do.","TWN":"我自己想做什麼？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정말 다른 사람을 돕고 싶은 건지…… 정말 다른 사람들과 친구가 되고 싶은 건지…….","JPN":"本当に他の人を助けたいのか……本当に他の人たちと友達になりたいのか……","ENG":"If I really wanted to help others... And whether I really wanted to become friends with them...","TWN":"我真的想幫助其他人嗎……我真的想和其他人做朋友嗎……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님은 병상에 누워 계시는 동안 언제나 제게 말씀하셨어요.","JPN":"お祖父様は入院している間、いつも私にこうおっしゃいました。","ENG":"When Grandfather was lying in his hospital bed, he would always say something to me.","TWN":"爺爺躺在病床上時，他經常對我說，"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저라면 <color=#ffd34c>더 나은 세상</color>을 만들 수 있을 거라고요.","JPN":"私なら<color=#ffd34c>より良い世界</color>が作れると。","ENG":"He said that I would make <color=#ffd34c>the world a better place</color>.","TWN":"我可以打造出<color=#ffd34c>更好的未來</color>。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……하지만 잘 모르겠어요.","JPN":"……でも、よくわかりません。","ENG":"But... I'm not so sure.","TWN":"……但我也不清楚，"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전 <color=#ffd34c>더 나은 세상</color>을 만들고 싶은 걸까요?","JPN":"私は<color=#ffd34c>より良い世界</color>を作りたいのでしょうか？","ENG":"Do I want to make <color=#ffd34c>the world a better place</color>?","TWN":"我真的想打造<color=#ffd34c>更好的未來</color>嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이제는……. 할아버님의 말씀에 따라도 되는 건지 모르겠어요.","JPN":"もう……お祖父様の言葉に従ってもいいのかすら、わからなくなりました。","ENG":"Now, I wonder... if I should even be following Grandfather’s words anymore.","TWN":"我……還要繼續聽從爺爺的吩咐嗎？"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님과 만나기 전까지는 이렇지 않았는데…….","JPN":"社長に出会うまではこんなことなかったのに……","ENG":"I wasn’t like this until I met you...","TWN":"在遇到老闆之前，我從來沒有想過這些事……"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님 말씀대로 제가 원하는 걸 떠올릴 때마다 가슴이 두근거리고, 머리가 아파요.","JPN":"社長のおっしゃるとおり、私が望むことを思い出すたびに胸がドキドキして、\\n頭が痛くなります。","ENG":"But whenever I think of something I want to do, my heart pounds but my head hurts.","TWN":"就像老闆說的，當我想到想要的東西時，心就會跳得很快，然後頭就會痛。"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"꼭……. 제가 나쁜 병이라도 걸린 것처럼요.","JPN":"まるで……悪い病気にかかった時みたいに。","ENG":"It’s almost as if... I’m sick with something.","TWN":"就好像……我得了什麼不治之症一樣。"},"stage":{"bg":"ALPHA_05","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그러니까…… 사장님이 대신 선택해 주세요!","JPN":"だから……社長が代わりに決めてください！","ENG":"So, I want you to choose for me!","TWN":"所以……請老闆幫我選吧！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"제가 앞으로 뭘 하면 되는지, 제가 앞으로 누굴 위해야 할지…….","JPN":"私がこれから何をすればいいのか、これから誰のために生きていけばいいのかを……","ENG":"What I need to do now, and who I should do it for...","TWN":"我以後該怎麼做，我以後該為誰賣命……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"말씀해 주시면 그대로 할게요. 저는 뭐든 할 수 있으니까요.","JPN":"決めていただければ、そのとおりにします。私は何でもできますから。","ENG":"If you tell me, I’ll do it. I can do anything.","TWN":"只要老闆告訴我，我一定照做！反正我什麼都做得到。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이런, 지아 양. 뭔가 오해하고 있나 보군.","JPN":"ユイ君、何か誤解しているようだな。","ENG":"Oh my, Jia... I’m afraid you misunderstood me.","TWN":"沈佳，你似乎有什麼誤會。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"미안하네만 그건 나도, 다른 누구도 해 줄 수 있는 일이 아니라네.","JPN":"悪いが、それは私にも、他の誰にもできることではない。","ENG":"Those are things only you can decide for yourself.","TWN":"抱歉，這件事不是我，或是其他人可以幫忙的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"설령 지아 양의 할아버지라고 할지라도 마찬가지지.","JPN":"それが例えユイのお祖父様でもな。","ENG":"Not even your grandfather can decide that for you.","TWN":"相信你的爺爺也是一樣的想法。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"지아 양, 어른들은……. 부모들은 항상 아이가 올바르게 크길 바란다네.","JPN":"ユイ君、大人は……親は常に、子どもに正しく育ってほしいと願っているよ。","ENG":"You see, Jia. Adults, well, parents want their children to grow up properly.","TWN":"沈佳，大人……父母通常都會有望子成龍的想法。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 그건 때때로 자기가 할 수 없었던 것을 아이에게 강요하는 형태가 되기도 하지.","JPN":"しかし、それは時々自分ができなかったことを子どもに強いる形になってしまう。","ENG":"However, this sometimes leads to them forcing their children to do things they weren't able to do when they were that age.","TWN":"但有時候，只是因為自己辦不到，而將自己的期待強加在孩子的身上。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"다른 사람의 말은 결국 자네가 살면서 참고할 이정표지, 목적지가 아니야.","JPN":"他人の言うことは、君が生きていく中で参考できる道しるべにはなるが、\\n目的地にはなれないんだ。","ENG":"What I'm trying to say is that what others say is a reference point in your life, not your final destination.","TWN":"其他人說的話，不能成為你的終點或目的地。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"목적지를 정하는 건 자네 자신의 마음에 달렸지.","JPN":"目的地を決めるのは君の心次第ってことだよ。","ENG":"Whichever direction you choose to go is entirely up to your heart.","TWN":"只有你的心能夠決定你的目的地！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"마음…….","JPN":"私の心……","ENG":"My heart...","TWN":"我的心……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만 사장님, 전 여태까지 할아버님 말씀대로만 해 왔는데…….","JPN":"でも社長、私はこれまでお祖父様の言うとおりに生きてきたのに……","ENG":"Th-then... I’ve lived my life according to Grandfather’s words all this time...","TWN":"可是老闆，我一直以來都是按著爺爺的話而活……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이제 와서 스스로 뭔가를 선택할 수 있을까요?","JPN":"今さら自分で何かを決めることができるのでしょうか？","ENG":"Will I still be able to make choices by myself?","TWN":"現在我還能夠自己做選擇嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아무렴! 물론이고 말고!","JPN":"ああ、もちろんだとも！","ENG":"Of course you can!","TWN":"那還用說！這是當然的！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"걱정 말게, 지아 양. 나는 자네가 잘할 거라고 믿고 있어.","JPN":"心配はいらないぞ、ユイ君。私は君ならできると信じている。","ENG":"Don’t worry, Jia. I believe you’ll do great.","TWN":"沒事的，沈佳！我相信你可以的！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……믿어 주신다고요?","JPN":"……信じてくださるのですか？","ENG":"Y-you do...?","TWN":"……老闆你相信我？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇지만 전……. 친구도 잘 못 사귀고……. 다른 분들을 언짢게만 하는데…….","JPN":"でも私は……友達作りも苦手で……他の方々を不快にさせてばかりで……","ENG":"B-but I... don’t know how to make friends... and I always make others feel uncomfortable...","TWN":"可是……我連交朋友都不會……只會惹人家生氣而已……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어허. 무슨 소린가. 자네가 사귄 친구가 여기 있는데.","JPN":"はあ、何を言っているんだ。君の友達が目の前にいるじゃないか。","ENG":"Hush! What are you talking about? You have a friend right in front of you.","TWN":"哈哈，你在胡說什麼，這裡不就有一個你交的朋友嗎！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"그라운드 원 도시관리국에서 알려드립니다.","JPN":"グラウンド・ワン、都市管理局からお知らせします。","ENG":"This is an announcement from Ground One, City Managements.","TWN":"G1城市管理局通知，"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 도시내에서 급성 침식 현상으로 인해 하급 침식체가 다수 출현했다는 소식입니다.","JPN":"現在、都市内での急性侵食現象により、下級侵食体が複数出現しています。","ENG":"We have received reports of multiple low-level Corrupted Objects being sighted downtown.","TWN":"現在發生緊急侵蝕現象，導致出現大量低階侵蝕體。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"담당 태스크포스가 대응 중이니, 시민 여러분께서는 경보가 해제되기 전까지는 안전한 곳에서 대기해 주시기 바랍니다.","JPN":"担当タスクフォースカンパニーが対応中ですので、市民の皆様は\\n警報が解除されるまで、安全な場所で待機してください。","ENG":"The respective TASKFORCEs with jurisdiction are responding to the situation. Please take shelter in safe areas until the alert is lifted.","TWN":"負責的特遣勢力正在處理中，請各位市民在警報解除前，至安全的地方等候。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"침식체가……?","JPN":"侵食体が……？","ENG":"Corrupted Objects...?","TWN":"侵蝕體……？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"너무 걱정 마세요, 손님! 이 도시는 대균열 때문에 소규모 침식사태가 자주 일어나거든요!","JPN":"あまり心配しないでください、お客様！　この都市は大亀裂のせいで\\n小規模侵食事態が頻繁に起きるんですよ。","ENG":"Please, don’t be alarmed! The Grand Dimension Crevice causes frequent small-scale Corruptions throughout the city.","TWN":"這位客人別擔心！這裡因為大峽谷的關係，經常會發生小規模的侵蝕事件！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"태스크포스들이 나서면 경보도 금방 해제될 거예요.","JPN":"タスクフォースカンパニーが対応すれば、警報もすぐに解除されます。","ENG":"It’ll soon be over when the TASKFORCEs take care of it.","TWN":"特遣勢力出動後，應該很會解除警報。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아무리 그래도……. 사람이 다치기라도 하면 큰일 아닐까요?","JPN":"でも……怪我人が出たらどうしましょう？","ENG":"But... What if someone gets hurt?","TWN":"可是……萬一這當中有人受傷的話怎麼辦？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다른 태스크포스 분들이 잘하고 계신지 얼른 보고 올게요.","JPN":"他のタスクフォースカンパニーの方々で間に合っているか、ちょっと見てきます。","ENG":"I’ll go check to see how the other TASKFORCEs are doing.","TWN":"我要去看一下特遣勢力處理得怎麼樣。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"여기서 잠시만 기다려 주세요, 사장님.","JPN":"ここで少々お待ちください、社長。","ENG":"Sir, I want you to stay put for a minute.","TWN":"老闆，麻煩你在這裡等我一下。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"손님, 그렇지만 관할 구역이란 게 있다던데……!","JPN":"お客様、でも管轄区域というのがあって……！","ENG":"But there are such things as jurisdictions...!","TWN":"客人，可是這裡是有分管轄區的……！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"아아, 가 버리셨네…….","JPN":"あ、もう行っちゃった……","ENG":"Ah... She’s gone already...","TWN":"哎呀，走這麼快……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후후. 자각만 못했지 자기 마음이 어떤지는 이미 잘 알고 있군.","JPN":"フフフ、自覚していないだけで、自分の心がどうしたいのか\\nよくわかっているじゃないか。","ENG":"Heh heh heh. She might not know it, but I can tell her heart has made up its mind already.","TWN":"呵呵呵，雖然本人還沒沒察覺到，但她的心已經很清楚該怎麼做。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"차근차근 인간과 가까워지면 되는 거야, 지아 양. 역시 내 안목은 틀리지를 않는군.","JPN":"少しずつ人間との距離を縮めていけばいいんだよ、ユイ君。\\nやはり私の目は正しかったな。","ENG":"I knew I saw something in her. Just take your time getting closer to humans, Jia.","TWN":"沈佳，你只需要一步一步變得像人就好，我的眼光果然沒錯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"앗! 맞다, 손님!","JPN":"あっ、そうだ！　お客様！","ENG":"Oh! Um, excuse me!","TWN":"對了！客人！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이거 영수증이에요! 먼저 가신 손님 것도 같이 계산 부탁드려요!","JPN":"領収書です！　先に行かれたお客様の分も一緒にお会計をお願いします！","ENG":"Here’s your bill! And don’t forget to pay for hers too!","TWN":"這是帳單！麻煩和剛剛那位客人的餐點一起買單！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그럼 전 급한 일이 있어서! 가자, 레일리!","JPN":"では、私は急用があるのでお先に失礼します！　行こう、レイリー！","ENG":"Sorry, I gotta go! Rayleigh, let’s go!","TWN":"那我還有急事！走吧，瑞利！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"비싸!! 스트레스를 간식으로 푸는 성격이었나?!","JPN":"高っ！？　ストレスをおやつで発散する性格だったのか！？","ENG":"THAT MUCH?! Was she the type to blow off steam with snacks?!","TWN":"好貴！！她是靠點心紓壓的類型嗎？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};